/*
 * remainder() test harness — prints (x_hex, y_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x, double y)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    g_acc += remainder(vx, vy);
#else
    double r = remainder(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

#ifndef EN_PERF
static void test_sweep(void)
{
    double divisors[] = { 0.5, 1.0, 1.5, 2.0, 2.5, 3.0, 3.5, 4.0 };
    int n = sizeof(divisors) / sizeof(divisors[0]);
    for (int i = 0; i < n; i++) {
        emit(10.0, divisors[i]);
        emit(-10.0, divisors[i]);
    }
}

static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
        0x4000000000000000ULL, /* 2.0 */
        0x4008000000000000ULL, /* 3.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i], 0x3ff0000000000000ULL);
}

static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        double x = -10.0 + 20.0 * (double)i / (double)(nx - 1);
        for (int j = 0; j < ny; j++) {
            double y = 0.1 + 4.9 * (double)j / (double)(ny - 1);
            emit(x, y);
        }
    }
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (12) --- */
    emit(0.0, 1.0);                                                              /* +0 numerator */
    emit(-0.0, 1.0);                                                             /* -0 numerator */
    emit(1.0, 0.0);                                                              /* zero divisor -> NaN */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN numerator, 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN numerator, 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -qNaN numerator, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN divisor */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf numerator -> NaN */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf numerator -> NaN */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL);  /* 1.0, +Inf divisor -> 1.0 */
    emit_u(0x3ff0000000000000ULL, 0xfff0000000000000ULL);  /* 1.0, -Inf divisor -> 1.0 */
    emit_u(0x7ff0000000000000ULL, 0x7ff0000000000000ULL);  /* +Inf, +Inf -> NaN */

    /* --- Section 2: Subnormal (denormal) inputs (8) --- */
    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL);  /* min positive subnormal: 2^-1074, y=1.0 */
    emit_u(0x8000000000000001ULL, 0x3ff0000000000000ULL);  /* min negative subnormal, y=1.0 */
    emit_u(0x0008000000000000ULL, 0x3ff0000000000000ULL);  /* mid subnormal, y=1.0 */
    emit_u(0x8008000000000000ULL, 0x3ff0000000000000ULL);  /* -mid subnormal, y=1.0 */
    emit_u(0x000fffffffffffffULL, 0x3ff0000000000000ULL);  /* max subnormal: just below DBL_MIN, y=1.0 */
    emit_u(0x800fffffffffffffULL, 0x3ff0000000000000ULL);  /* -max subnormal, y=1.0 */
    emit_u(0x3ff0000000000000ULL, 0x0000000000000001ULL);  /* 1.0, min positive subnormal divisor */
    emit_u(0x3ff0000000000000ULL, 0x000fffffffffffffULL);  /* 1.0, max subnormal divisor */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN, 1.0);                                                          /* smallest normal positive */
    emit(-DBL_MIN, 1.0);                                                         /* smallest normal negative */
    emit_u(0x0010000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above DBL_MIN */
    emit(DBL_MAX, 1.0e200);                                                      /* near DBL_MAX */
    emit(-DBL_MAX, 1.0e200);                                                     /* near -DBL_MAX */
    emit_u(0x7fefffffffffffffULL, 0x7fe0000000000000ULL);  /* DBL_MAX, large divisor */

    /* --- Section 4: Near 1.0 density (8) --- */
    emit_u(0x3fefffffffffffffULL, 0x3fe0000000000000ULL);  /* one ULP below 1.0, y=0.5 */
    emit(1.0, 0.5);                                                              /* exact quotient 2.0 */
    emit_u(0x3ff0000000000001ULL, 0x3fe0000000000000ULL);  /* one ULP above 1.0, y=0.5 */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP below 1.0, y=1.0 */
    emit(1.0, 1.0);                                                              /* remainder = 0 */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above 1.0, y=1.0 */
    emit(-1.0, 1.0);                                                             /* negative x at -1 */
    emit_u(0xbfefffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP toward zero from -1.0 */

    /* --- Section 5: Sign combinations (8) --- */
    emit(5.0, 2.0);                                                              /* +x, +y: result +1 */
    emit(-5.0, 2.0);                                                             /* -x, +y: result -1 */
    emit(5.0, -2.0);                                                             /* +x, -y: result +1 */
    emit(-5.0, -2.0);                                                            /* -x, -y: result -1 */
    emit(5.5, 2.5);                                                              /* +x, +y: result -0.0... actually +0.5 */
    emit(-5.5, 2.5);                                                             /* -x, +y */
    emit(7.0, 2.5);                                                              /* +x, +y: 7 = 2*2.5 + 2, round to 3*2.5? -> -0.5 */
    emit(-7.0, 2.5);                                                             /* -x, +y */

    /* --- Section 6: Mathematical properties - exact divisibility and half-step (12) --- */
    emit(10.0, 5.0);                                                             /* x = 2*y: remainder = 0 */
    emit(15.0, 5.0);                                                             /* x = 3*y: remainder = 0 */
    emit(100.0, 10.0);                                                           /* x = 10*y: remainder = 0 */
    emit(-20.0, 4.0);                                                            /* negative exact: remainder = 0 */
    emit(0.5, 0.5);                                                              /* x = y: remainder = 0 */
    emit(3.0, 2.0);                                                              /* remainder = -1 (nearest even) */
    emit(1.5, 0.5);                                                              /* remainder = 0 (3 half-steps) */
    emit(22.0, 7.0);                                                             /* near pi approximation */
    emit(-22.0, 7.0);                                                            /* negative near-pi */
    emit(355.0, 113.0);                                                          /* better pi approximation */
    emit(100.0, 30.0);                                                           /* mixed */
    emit(-100.0, 30.0);                                                          /* negative mixed */

    /* --- Section 7: Large magnitude pairs (10) --- */
    emit(1.0e100, 1.0e50);                                                       /* very large x, large y */
    emit(1.0e200, 1.0e100);                                                      /* extreme large */
    emit(-1.0e100, 1.0e50);                                                      /* negative large x */
    emit(1.0e50, 1.0e100);                                                       /* x < y: result = x */
    emit(1.0e15, 3.0);                                                           /* large x, small y */
    emit(1.0e16, 7.0);                                                           /* larger x, small y */
    emit(1.0e17, 11.0);                                                          /* stress integer representation */
    emit(-1.0e15, 3.0);                                                          /* negative large x, small y */
    emit(1.23456789012345e15, 1.0);                                              /* large non-round x */
    emit(DBL_MAX, 1.0e100);                                                      /* DBL_MAX with large divisor */

    /* --- Section 8: Near-integer and half-integer boundaries (12) --- */
    emit(1.5, 1.0);                                                              /* half-integer: remainder = -0.5 */
    emit(2.5, 1.0);                                                              /* half-integer: remainder = -0.5 */
    emit(-1.5, 1.0);                                                             /* negative half-integer */
    emit(-2.5, 1.0);                                                             /* negative half-integer */
    emit(0.5, 1.0);                                                              /* x < y: remainder = 0.5 */
    emit(-0.5, 1.0);                                                             /* x > -y: remainder = -0.5 */
    emit(1.0000000000000002, 1.0);                                               /* one ULP above 1, y=1: tiny positive */
    emit(0.9999999999999998, 1.0);                                               /* one ULP below 1, y=1: tiny negative */
    emit(10.5, 1.0);                                                             /* half-integer large */
    emit(-10.5, 1.0);                                                            /* negative half-integer large */
    emit(100.5, 1.0);                                                            /* larger half-integer */
    emit(0.25, 0.5);                                                             /* x = 0.5*y: remainder = 0.25 */

    /* --- Section 9: Mixed magnitude (x >> y and x << y) (12) --- */
    emit(1.0e-100, 1.0e-50);                                                     /* tiny x, moderate y: remainder = x */
    emit(1.0e-200, 1.0e-100);                                                    /* very tiny x, tiny y: remainder = x */
    emit(1.0e-50, 1.0e-100);                                                     /* x >> y, both tiny */
    emit(DBL_MIN, DBL_MIN);                                                      /* x = y: remainder = 0 */
    emit(2.0 * DBL_MIN, DBL_MIN);                                                /* x = 2*y: remainder = 0 */
    emit(3.0 * DBL_MIN, DBL_MIN);                                                /* x = 3*y: remainder = 0 */
    emit(1.0, 1.0e-10);                                                          /* large x relative to y */
    emit(1.0, 1.0e-15);                                                          /* even larger ratio */
    emit(1.0e10, 1.0e-5);                                                        /* extreme ratio */
    emit(1.0, 3.0);                                                              /* x < y: remainder = 1.0 */
    emit(2.0, 3.0);                                                              /* x < 1.5*y: remainder = -1.0 */
    emit(0.1, 0.3);                                                              /* floating-point inexact */

    /* --- Section 10: Hard cases and ULP neighbors of result boundaries (12) --- */
    emit_u(0x4000000000000000ULL, 0x3ff0000000000000ULL);  /* 2.0, 1.0: remainder = 0 */
    emit_u(0x4008000000000000ULL, 0x3ff0000000000000ULL);  /* 3.0, 1.0: remainder = 0 */
    emit_u(0x400921fb54442d18ULL, 0x3ff0000000000000ULL);  /* pi, 1.0 */
    emit_u(0x400921fb54442d18ULL, 0x4000000000000000ULL);  /* pi, 2.0 */
    emit_u(0x400921fb54442d18ULL, 0x400921fb54442d18ULL);  /* pi, pi: remainder = 0 */
    emit_u(0x401921fb54442d18ULL, 0x3ff921fb54442d18ULL);  /* 2pi, pi/2: remainder = 0 */
    emit_u(0x3fe62e42fefa39efULL, 0x3fe0000000000000ULL);  /* ln2, 0.5 */
    emit_u(0x3ff0000000000000ULL, 0x3fe62e42fefa39efULL);  /* 1.0, ln2 */
    emit(5.0, 3.0);                                                              /* 5 = 1*3 + 2, but |2| > 1.5 -> -1 */
    emit(-5.0, 3.0);                                                             /* -5, 3: result = 1 */
    emit(4.0, 3.0);                                                              /* 4 = 1*3 + 1: remainder = 1 */
    emit(-4.0, 3.0);                                                             /* -4, 3: remainder = -1 */
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

